sql:
SELECT AVG(rating) AS average_rating
FROM products p
JOIN product_reviews pr ON p.product_id = pr.product_id;

external_knowledge:
- "longer lifespan" refers to products with a lifetime of at least 5000 hours;
- "more than a dozen" means the sale quantity is greater than 10;
- The "average selling price" is the average of the sale price for each unique combination of product type, voltage, and brand.

sql:
SELECT warehouse_id, SUM(quantity) AS total_products
FROM product_inventory
GROUP BY warehouse_id;
